175	// ---------------------------------------------------------------------------
176	// Pricing options
177	// ---------------------------------------------------------------------------
178	
179	export interface PricingHooks {
180	  beforeStage?(stageName: string): void;
181	  afterStage?(stageName: string, runningTotal: number): void;
182	}
183	
184	export interface PricingOptions {
185	  vatRate?: number;
186	  /** Only half-up rounding is implemented; the enum anticipates bankers'. */
187	  roundingMode?: "half-up";
188	  /** Reserved for localised price formatting. */
189	  locale?: string;
190	  /** Observability hooks invoked around every pipeline stage. */
191	  hooks?: PricingHooks;
192	}
193	
194	const DEFAULT_PRICING_OPTIONS: Required<Omit<PricingOptions, "hooks">> = {
195	  vatRate: 0.2,
196	  roundingMode: "half-up",
197	  locale: "en-GB",
198	};
199	
200	function resolveOptions(
201	  options?: PricingOptions,
202	): Required<Omit<PricingOptions, "hooks">> & { hooks: PricingHooks } {
203	  return {
204	    ...DEFAULT_PRICING_OPTIONS,
205	    ...(options ?? {}),
206	    hooks: options?.hooks ?? {},
207	  };
208	}
