278	class SubtotalStage implements PipelineStage {
279	  readonly stageName = "subtotal";
280	
281	  private lineTotal(item: OrderItem): number {
282	    return item.unitPrice * item.quantity;
283	  }
284	
285	  execute(context: PricingContext): void {
286	    let total = new MoneyValue(0, context.order.currency);
287	    for (const item of context.order.items) {
288	      total = total.plus(
289	        new MoneyValue(this.lineTotal(item), context.order.currency),
290	      );
291	    }
292	    context.running = total;
293	  }
294	}
295	
296	class DiscountStage implements PipelineStage {
297	  readonly stageName = "discount";
298	
299	  constructor(private readonly registry: DiscountStrategyRegistry) {}
300	
301	  execute(context: PricingContext): void {
302	    let result = context.running.amount();
303	    for (const strategy of this.registry.all()) {
304	      if (strategy.applies(context.order)) {
305	        result = strategy.apply(result);
306	      }
307	    }
308	    context.running = context.running.withAmount(result);
309	  }
310	}
311	
312	class TaxStage implements PipelineStage {
313	  readonly stageName = "tax";
314	
315	  execute(context: PricingContext): void {
316	    context.running = context.running.times(1 + context.options.vatRate);
317	  }
318	}
